+}
+
+/// Map a key label to a stable action ID.
+fn action_id_for_label(label: &str) -> &'static str {
+    match label {
+        "1-8" | "1-9" => "jump_screen",
+        "Tab" => "next_screen",
+        "Shift+Tab" => "prev_screen",
+        "m" => "toggle_mode",
+        "Ctrl+P" => "command_palette_ctrl",
+        ":" => "command_palette",
+        "T" => "cycle_theme",
+        "?" => "toggle_help",
+        "q" => "quit",
+        "Esc" => "dismiss",
+        _ => "unknown",
+    }
+}
